    } else if (rating == "A") {
        return "可控风险";
    } else if (rating == "BBB") {
        return "一般风险";
    } else if (rating == "BB") {
        return "较高风险";
    } else if (rating == "B") {
        return "高风险";
    } else {
        return "极高风险";
    }
}


str def getSuggestion(str:rating) {
    if (rating == "AAA") {
        return "绿色通道，额度放宽20%";
    } else if (rating == "AA") {
